const n=JSON.parse('{"key":"v-63b8ed66","path":"/detail/019.html","title":"webpack逆向通用流程","lang":"zh-CN","frontmatter":{"layout":"Detail","title":"webpack逆向通用流程","date":"2024-09-13T00:00:00.000Z","description":"webpack内加密函数的快速处理流程","category":["JavaScript"],"tags":["JavaScript","Reverse"],"head":[["meta",{"property":"og:url","content":"https://saynop.github.io/detail/019.html"}],["meta",{"property":"og:title","content":"webpack逆向通用流程"}],["meta",{"property":"og:description","content":"webpack内加密函数的快速处理流程"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"article:tag","content":"JavaScript"}],["meta",{"property":"article:tag","content":"Reverse"}],["meta",{"property":"article:published_time","content":"2024-09-13T00:00:00.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"webpack逆向通用流程\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2024-09-13T00:00:00.000Z\\",\\"dateModified\\":null,\\"author\\":[]}"]]},"headers":[{"level":2,"title":"webpack原理","slug":"webpack原理","link":"#webpack原理","children":[]},{"level":2,"title":"加密函数的定位","slug":"加密函数的定位","link":"#加密函数的定位","children":[]},{"level":2,"title":"webpack调试流程","slug":"webpack调试流程","link":"#webpack调试流程","children":[{"level":3,"title":"明确分发编号","slug":"明确分发编号","link":"#明确分发编号","children":[]},{"level":3,"title":"分发器(加载器)定位","slug":"分发器-加载器-定位","link":"#分发器-加载器-定位","children":[{"level":4,"title":"特征","slug":"特征","link":"#特征","children":[]},{"level":4,"title":"定位","slug":"定位","link":"#定位","children":[]}]},{"level":3,"title":"处理加密函数","slug":"处理加密函数","link":"#处理加密函数","children":[]}]},{"level":2,"title":"解密","slug":"解密","link":"#解密","children":[]},{"level":2,"title":"总结","slug":"总结","link":"#总结","children":[]}],"git":{"updatedTime":null,"contributors":[]},"filePathRelative":"detail/019.md","excerpt":"<h2> webpack原理</h2>\\n<p>为了降低依赖，减轻负担，前端通常使用按需加载的方式。webpack将代码编号，在使用时分发器读取加载当前涉及到的编号内容，实现按需加载</p>\\n<p>以下是一段伪代码用于理解 webpack 的执行逻辑</p>\\n<ul>\\n<li>全部代码: 通过一个大对象内，每个key是不同的函数实现函数的分离。本文将 key 称为分发器编号，通常为数字或字符串<div class=\\"language-javascript line-numbers-mode\\" data-ext=\\"js\\"><pre class=\\"language-javascript\\"><code><span class=\\"token keyword\\">var</span> a <span class=\\"token operator\\">=</span> <span class=\\"token punctuation\\">{</span>\\n    <span class=\\"token number\\">923</span><span class=\\"token operator\\">:</span> <span class=\\"token keyword\\">function</span><span class=\\"token punctuation\\">(</span><span class=\\"token parameter\\">e<span class=\\"token punctuation\\">,</span> t<span class=\\"token punctuation\\">,</span> n</span><span class=\\"token punctuation\\">)</span> <span class=\\"token punctuation\\">{</span><span class=\\"token punctuation\\">}</span>\\n    <span class=\\"token number\\">120</span><span class=\\"token operator\\">:</span> <span class=\\"token punctuation\\">(</span><span class=\\"token parameter\\">e<span class=\\"token punctuation\\">,</span> t<span class=\\"token punctuation\\">,</span> n</span><span class=\\"token punctuation\\">)</span> <span class=\\"token operator\\">=&gt;</span> <span class=\\"token punctuation\\">{</span><span class=\\"token punctuation\\">}</span>\\n    <span class=\\"token number\\">6122</span><span class=\\"token operator\\">:</span> <span class=\\"token punctuation\\">(</span><span class=\\"token punctuation\\">)</span> <span class=\\"token operator\\">=&gt;</span> <span class=\\"token punctuation\\">{</span><span class=\\"token punctuation\\">}</span>\\n<span class=\\"token punctuation\\">}</span>\\n</code></pre><div class=\\"line-numbers\\" aria-hidden=\\"true\\"><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div></div></div></li>\\n<li>已加载代码: 一个空对象用于存放当前已加载的内容。当使用到未加载编号时将代码装载到这个对象，后续再次使用时，直接从此对象获取</li>\\n<li>分发器(加载器)用于加载大对象内对应编号的代码。先检查已加载代码的对象内是否含有此编号，是则直接返回，否则从全部代码中读取并填装到该对象<div class=\\"language-javascript line-numbers-mode\\" data-ext=\\"js\\"><pre class=\\"language-javascript\\"><code><span class=\\"token comment\\">// 本函数名 n</span>\\n<span class=\\"token comment\\">// r 是编号，t 是已加载代码的对象, e 包含全部代码的对象</span>\\n\\n<span class=\\"token comment\\">// 已加载</span>\\n<span class=\\"token keyword\\">if</span> <span class=\\"token punctuation\\">(</span>t<span class=\\"token punctuation\\">[</span>r<span class=\\"token punctuation\\">]</span><span class=\\"token punctuation\\">)</span> <span class=\\"token keyword\\">return</span> t<span class=\\"token punctuation\\">[</span>r<span class=\\"token punctuation\\">]</span><span class=\\"token punctuation\\">.</span>exports\\n<span class=\\"token comment\\">// 未加载</span>\\n<span class=\\"token comment\\">// 初始化</span>\\n<span class=\\"token keyword\\">var</span> i <span class=\\"token operator\\">=</span> t<span class=\\"token punctuation\\">[</span>r<span class=\\"token punctuation\\">]</span> <span class=\\"token operator\\">=</span> <span class=\\"token punctuation\\">{</span><span class=\\"token literal-property property\\">exports</span><span class=\\"token operator\\">:</span> <span class=\\"token punctuation\\">{</span><span class=\\"token punctuation\\">}</span><span class=\\"token punctuation\\">}</span>\\n<span class=\\"token comment\\">// 加载 - 先将代码放入 i.exports，再返回 i.exports</span>\\n<span class=\\"token keyword\\">return</span> e<span class=\\"token punctuation\\">[</span>r<span class=\\"token punctuation\\">]</span><span class=\\"token punctuation\\">.</span><span class=\\"token function\\">call</span><span class=\\"token punctuation\\">(</span>i<span class=\\"token punctuation\\">.</span>exports<span class=\\"token punctuation\\">,</span> i<span class=\\"token punctuation\\">,</span> i<span class=\\"token punctuation\\">.</span>exports<span class=\\"token punctuation\\">,</span> n<span class=\\"token punctuation\\">)</span><span class=\\"token punctuation\\">,</span> i<span class=\\"token punctuation\\">.</span>exports\\n</code></pre><div class=\\"line-numbers\\" aria-hidden=\\"true\\"><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div></div></div></li>\\n<li>主逻辑代码<div class=\\"language-javascript line-numbers-mode\\" data-ext=\\"js\\"><pre class=\\"language-javascript\\"><code><span class=\\"token comment\\">// 使用加载器导入对应编号的函数，实现导入功能</span>\\n<span class=\\"token keyword\\">var</span> result <span class=\\"token operator\\">=</span> <span class=\\"token function\\">n</span><span class=\\"token punctuation\\">(</span><span class=\\"token number\\">120</span><span class=\\"token punctuation\\">)</span>\\nconsole<span class=\\"token punctuation\\">.</span><span class=\\"token function\\">log</span><span class=\\"token punctuation\\">(</span>result<span class=\\"token punctuation\\">)</span>\\n</code></pre><div class=\\"line-numbers\\" aria-hidden=\\"true\\"><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div></div></div></li>\\n</ul>"}');export{n as data};
